using UnityEngine;  public class Enemy_Stats : MonoBehaviour {     [Header("基礎血量設定")]     public float maxHealth = 100f;     private float currentHealth;      [Header("移動速度設定")]     public float baseSpeed = 2f;     private float currentSpeed;     private float slowTimer = 0f;       [Header("金幣")]     public int goldReward = 10;       private bool isDead = false;     void Start()     {         currentHealth = maxHealth;          // 🎯 遊戲一開始，當前速度就等於原始速度         currentSpeed = baseSpeed;     }      void Update()     {         // 1. 執行怪物的移動         MoveEnemy();          // 2. ⏳ 緩速計時器倒數         if (slowTimer > 0f)         {             slowTimer -= Time.deltaTime;             if (slowTimer <= 0f)             {                 RestoreSpeed(); // 時間到，恢復正常速度             }         }     }      // 🏃 這是在 Stats 內部直接處理的移動邏輯     private void MoveEnemy()     {         // 🎯 【關鍵點】移動時，必須乘以 currentSpeed，而不是 baseSpeed！         // 這樣當盆栽塔改變 currentSpeed 時，怪物的移動速度才會即時變慢。         transform.Translate(Vector3.forward * currentSpeed * Time.deltaTime);          // 💡 提示：如果你原本是用路徑點 (Waypoints) 移動，程式碼可能長這樣：         // Vector3 dir = targetWaypoint.position - transform.position;         // transform.Translate(dir.normalized * currentSpeed * Time.deltaTime, Space.World);     }
    public void TakeDamage(float damageAmount)     {
        // 🎯 1. 核心攔截：如果已經被判定死亡，後續任何子彈補刀直接無視！
        if (isDead) return;          currentHealth -= damageAmount;

        if (currentHealth <= 0)         {             Die();         }     }

    // 🎯 盆栽塔呼叫的緩速方法
    public void ApplySlow(float slowFactor, float duration)     {         // 假設 baseSpeed = 2，盆栽傳入 slowFactor = 0.5f         // currentSpeed 就會變成 2 * 0.5 = 1 (速度直接砍半！)         currentSpeed = baseSpeed * slowFactor;          // 給予或刷新緩速持續秒數         slowTimer = duration;          Debug.Log($"🌵 {gameObject.name} 被盆栽緩速！當前速度降為：{currentSpeed}，持續 {duration} 秒");     }      // 🏃 恢復原始速度     private void RestoreSpeed()     {         // 時間到了，把當前速度調回原本滿速的狀態         currentSpeed = baseSpeed;         Debug.Log($"✨ {gameObject.name} 緩速結束，恢復正常速度：{currentSpeed}");     }  private void Die()     {         // 🎯 2. 關鍵防護：一進來立刻標記為已死亡，把鎖鎖死！         isDead = true;          Debug.Log($"{gameObject.name} 被擊殺了！");          // 🪙 【核心串接】呼叫金幣管理器加錢！（此時只會被觸發唯一一次）         if (Money_Manager.instance != null)         {             Money_Manager.instance.AddGold(goldReward);         }         else         {             Debug.LogWarning("找不到 Money_Manager，無法獲得金幣！");         }          // 💀 銷毀怪物物件         Destroy(gameObject);     }  }